commit db1ea9481054448d97ae43bd082147e7d6ba5501
Author: Tariq <tibrahim@nvidia.com>
Date:   Mon Jun 1 16:01:40 2026 -0700

    fix index out of range panic in findPidToSignal (#1822)

    Co-authored-by: Sai Asish Y say.apm35@gmail.com

    Signed-off-by: Tariq Ibrahim <tibrahim@nvidia.com>
---
 cmd/config-manager/main.go | 3 +++
 1 file changed, 3 insertions(+)

diff --git a/cmd/config-manager/main.go b/cmd/config-manager/main.go
index 6c21a4b0c..1d30d45d6 100644
--- a/cmd/config-manager/main.go
+++ b/cmd/config-manager/main.go
@@ -453,6 +453,9 @@ func findPidToSignal(f *Flags) (int, error) {
 		if err != nil {
 			return -1, fmt.Errorf("error getting cmdline: %v", err)
 		}
+		if len(cmdline) == 0 {
+			continue
+		}
 		if cmdline[0] == f.ProcessToSignal {
 			return p.PID, nil
 		}

